2101→\begin{lemma}[{\cite[\href{https://stacks.math.columbia.edu/tag/09AZ}{Tag 09AZ}, second part in the proof of (3) $\implies$ (1)]{stacks-project}}]
2102→  \label{thm:ff-identifies-local-rings-plus-c-has-retraction-if}
2103→  \uses{def:w-local-ring,def:extremally-disconnected,def:identify-local-rings}
2104→  Let $A$ be a ring. If the following two conditions hold:
2105→  \begin{enumerate}
2106→    \item $A$ is w-local, and
2107→    \item $\pi_0(\operatorname{Spec}(A))$ is extremally disconnected.
2108→  \end{enumerate}
2109→  Then every faithfully flat ring map $A \to B$ identifying local rings with \(B\) w-local and whose closed points of \(\Spec (B)\) are exactly \(V(IB)\) has a retraction.
2110→\end{lemma}
